('business:2-4-4-promotion:match:8a99b52e', 'business', 'business:2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Promotion”?", "options": ["Informing customers about a product or service and persuading them to buy it.", "Offers available at the exact time and place of purchase, designed to tempt an immediate sale.", "The various communication channels used to broadcast a message to a wider audience (e.g., TV, Radio, Social Media).", "A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items."]}'::jsonb, '{"answer": 0, "explain": "“Promotion” means: Informing customers about a product or service and persuading them to buy it."}'::jsonb),
('business:2-4-4-promotion:match:47da2219', 'business', 'business:2-4-4-promotion', '2.4.4 Promotion', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Point of Sale Promotion”?", "options": ["Offers available at the exact time and place of purchase, designed to tempt an immediate sale.", "The various communication channels used to broadcast a message to a wider audience (e.g., TV, Radio, Social Media).", "A product sold at a financial loss to attract customers into a store, hoping they buy other profitable items.", "Giving away a small amount of a product (like food or cosmetics) to persuade consumers to try it."]}'::jsonb, '{"answer": 0, "explain": "“Point of Sale Promotion” means: Offers available at the exact time and place of purchase, designed to tempt an immediate sale."}'::jsonb),
