('business:2-4-5-place:exam:6ffeb3cc', 'business', 'business:2-4-5-place', '2.4.5 Place', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of the following is true about a wholesaler?", "options": ["They manufacture raw materials into finished products", "They buy in bulk from producers and sell in smaller quantities to retailers", "They only sell directly to the final consumer", "They design television advertising campaigns"], "hint": "Think about the term ''breaking bulk''.", "starter": "A wholesaler''s main job is to..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B</strong></p><p>This describes the process of ''breaking bulk'', which is the primary function of a wholesaler in the distribution channel.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-4-5-place:mcq:e2ca3ab8', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "Digital distribution is best suited to:", "options": ["selling goods and services from a high-street shop", "selling goods and services through a massive warehouse", "selling and delivering goods in a digital, electronic format", "selling goods and services at airports"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Digital distribution involves sending products electronically over the internet, like music streams or software downloads."}'::jsonb),
('business:2-4-5-place:mcq:16109c18', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "A distribution channel is defined as:", "options": ["a method of improving the physical quality of goods", "the path taken to get goods and services from the producer to the customer", "a method of advertising products on digital television", "the physical location of the factory where goods are made"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A distribution channel is the journey a product takes from the manufacturer to the final end-user."}'::jsonb),
('business:2-4-5-place:mcq:8087abf0', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "Which of the following products would be suited to BOTH physical and digital distribution?", "options": ["Potatoes", "Newspapers", "Luxury Watches", "Designer Clothes"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Newspapers can be bought physically in a shop or read digitally via a tablet app. The others can only be distributed physically."}'::jsonb),
('business:2-4-5-place:mcq:f179bb68', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "What is the primary role of a wholesaler in a distribution channel?", "options": ["To manufacture the goods from raw materials", "To ''break bulk'' by buying massive quantities and selling them in smaller boxes", "To sell single items directly to the final consumer", "To create advertising campaigns for television"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Wholesalers buy in massive bulk from producers and break it down into smaller, affordable quantities for independent retailers."}'::jsonb),
('business:2-4-5-place:mcq:e7920ba4', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "Which distribution channel is represented by: Producer → Consumer?", "options": ["Channel 1", "Channel 2", "Channel 3", "Wholesale Channel"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. Channel 1 is direct selling, with no intermediaries (middlemen) between the maker and the buyer."}'::jsonb),
('business:2-4-5-place:mcq:bd176384', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "Why might a massive paint manufacturer like Dulux choose to sell directly to large retailers (like B&Q) instead of using a wholesaler?", "options": ["Because B&Q cannot afford to buy in bulk", "To keep the profit margin that would normally be taken by the wholesaler", "Because wholesalers only sell digital products", "Because Dulux wants to personally sell paint to individual homeowners"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Cutting out the wholesaler (the middleman) allows the producer to keep a larger share of the profit."}'::jsonb),
('business:2-4-5-place:mcq:96440572', 'business', 'business:2-4-5-place', '2.4.5 Place', 'mcq', 'mcq', 1, '{"question": "Which of the following is a major disadvantage of DIGITAL distribution?", "options": ["The business has to close at 5:00 PM every day", "Digital content can be easily copied and illegally shared for free", "It limits the business to only selling to local customers", "The physical transport costs (lorries and fuel) are very high"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Piracy (illegal copying and sharing) is a massive threat to digital products like music, films, and software."}'::jsonb)
